const config = $("Config").first().json;
const weather = $input.first().json;

const weights = config.weights;
const monthlyRanges = config.monthly_temp_ranges;

const scoredDays = [];

for (let i = 0; i < weather.daily.time.length; i++) {
  const date = weather.daily.time[i];
  const temp = weather.daily.temperature_2m_max[i];
  const apparentTemp = weather.daily.apparent_temperature_max[i];
  const precip = weather.daily.precipitation_probability_max[i];
  const precipSum = weather.daily.precipitation_sum[i];
  const precipHours = weather.daily.precipitation_hours[i];
  const wind = weather.daily.windspeed_10m_max[i];
  const humidity = weather.daily.relative_humidity_2m_max[i];

  // Convert precipitation from mm to inches
  const precipInches = precipSum / 25.4;

  // Precipitation veto: if actual rain > 0.3 inches OR rain hours > 4, force Indoor
  const precipVeto = precipInches > 0.3 || precipHours > 4;

  if (precipVeto) {
    scoredDays.push({
      date,
      score: 0,
      band: 'Indoor',
      temp,
      apparentTemp,
      precip,
      precipInches,
      wind,
      humidity,
      notes: 'Rain likely most of the day, stay inside'
    });
    continue;
  }

  // Get month from date
  const month = new Date(date).getMonth() + 1;
  const [minTemp, maxTemp] = monthlyRanges[month];

  // Calculate component scores (0-100)
  // Apparent Temperature: 100 if in range, decreases as it goes outside
  let tempScore = 100;
  if (apparentTemp < minTemp) {
    tempScore = Math.max(0, 100 - (minTemp - apparentTemp) * 5);
  } else if (apparentTemp > maxTemp) {
    tempScore = Math.max(0, 100 - (apparentTemp - maxTemp) * 5);
  }

  // Precipitation probability: 100 at 0%, 0 at 100%
  const precipScore = 100 - precip;

  // Wind: Tighter thresholds
  // 0-10mph = 100pts, 11-15mph = 70pts, 16-20mph = 40pts, 21-25mph = 15pts, over 25mph = 0pts
  let windScore;
  if (wind <= 10) windScore = 100;
  else if (wind <= 15) windScore = 70;
  else if (wind <= 20) windScore = 40;
  else if (wind <= 25) windScore = 15;
  else windScore = 0;

  // Humidity: optimal at 50%, decreases as it moves away
  const humidityScore = Math.max(0, 100 - Math.abs(humidity - 50) * 2);

  // Weighted score
  let score = Math.round(
    tempScore * weights.temp +
    precipScore * weights.precip +
    windScore * weights.wind +
    humidityScore * weights.humidity
  );

  // Apply vetos and caps
  // Month-aware feels-like temperature floor
  // Jan/Feb = 25°F, Mar/Apr = 28°F, May/Jun = 40°F, Jul/Aug = 55°F, Sep/Oct = 35°F, Nov/Dec = 28°F
  let monthlyMinTemp;
  if (month === 1 || month === 2) monthlyMinTemp = 25;
  else if (month === 3 || month === 4) monthlyMinTemp = 28;
  else if (month === 5 || month === 6) monthlyMinTemp = 40;
  else if (month === 7 || month === 8) monthlyMinTemp = 55;
  else if (month === 9 || month === 10) monthlyMinTemp = 35;
  else monthlyMinTemp = 28; // Nov/Dec

  if (apparentTemp < monthlyMinTemp) {
    score = Math.min(score, 25); // Indoor cap
  }

  // Freezing cap: below 32°F can never be better than Marginal
  if (apparentTemp < 32) {
    score = Math.min(score, 59); // Marginal maximum
  }

  // Feels-like Prime block: below 40°F can never be Prime
  if (apparentTemp < 40) {
    score = Math.min(score, 79); // Good maximum
  }

  // Summer heat ceiling: above 95°F cap at Marginal, above 103°F cap at Indoor
  if (apparentTemp > 103) {
    score = Math.min(score, 35); // Indoor maximum
  } else if (apparentTemp > 95) {
    score = Math.min(score, 59); // Marginal maximum
  }

  // Combined bad condition veto: wind + cold
  // May-Oct: wind > 18mph AND apparent temp < 45°F
  // Mar-Apr: wind > 22mph AND apparent temp < 45°F (softer threshold for early spring)
  if (month >= 5 && month <= 10) {
    if (wind > 18 && apparentTemp < 45) {
      score = Math.min(score, 35);
    }
  } else if (month === 3 || month === 4) {
    if (wind > 22 && apparentTemp < 45) {
      score = Math.min(score, 35);
    }
  }

  // Wind veto: > 25mph cap at 25 (Indoor), > 20mph cap at 45 (Marginal max), 16-20mph cap at 65 (Good max, lower end)
  if (wind > 25) {
    score = Math.min(score, 25);
  } else if (wind > 20) {
    score = Math.min(score, 45);
  } else if (wind >= 16) {
    score = Math.min(score, 65); // Good maximum, lower end
  }

  // Determine band
  let band;
  if (score >= 80) band = 'Prime';
  else if (score >= 60) band = 'Good';
  else if (score >= 40) band = 'Marginal';
  else band = 'Indoor';

  // Generate narrative notes (max 12 words)
  let notes = '';
  if (apparentTemp > 103) {
    notes = 'Extreme heat, unsafe for outdoor work';
  } else if (apparentTemp > 95) {
    notes = 'Very hot, take frequent breaks and hydrate';
  } else if (wind > 25) {
    notes = 'High wind makes outdoor work difficult';
  } else if (wind > 20) {
    notes = 'Strong winds, challenging conditions';
  } else if (apparentTemp < monthlyMinTemp) {
    notes = 'Too cold for safe outdoor work';
  } else if (apparentTemp < 32) {
    notes = 'Freezing temps, limited outdoor work possible';
  } else if (wind > 18 && apparentTemp < 45 && month >= 5 && month <= 10) {
    notes = 'Cold and windy, uncomfortable combination';
  } else if (wind > 22 && apparentTemp < 45 && (month === 3 || month === 4)) {
    notes = 'Cold and windy, uncomfortable combination';
  } else if (apparentTemp < 40) {
    notes = 'Cold but calm and dry, bundle up';
  } else if (wind >= 16) {
    notes = 'Moderate wind, some tasks may be difficult';
  } else if (band === 'Prime') {
    notes = 'Ideal conditions, low wind and comfortable temps';
  } else if (band === 'Good') {
    notes = 'Good day for outdoor work';
  } else if (band === 'Marginal') {
    notes = 'Workable but not ideal conditions';
  } else {
    notes = 'Indoor work recommended';
  }

  scoredDays.push({
    date,
    score,
    band,
    temp,
    apparentTemp,
    precip,
    precipInches,
    wind,
    humidity,
    notes
  });
}

return scoredDays.map(day => ({ json: day }));
